import React, { useState, useEffect, createContext, useContext } from 'react';

// Building Materials Marketplace - Demo Single File React App
// Default export a component that demonstrates:
// - Roles: superadmin, supplier, supplier-admin, user, delivery
// - Supplier registration + admin console for supplier to CRUD products
// - Super admin control for categories and activating/deactivating suppliers
// - Marketplace UI with filters, sort, cart, checkout (AED) and invoice modal
// - Order flows: when order placed it appears in Delivery interface; driver marks delivered
// Note: This is a demo app using local state + localStorage as a fake backend.

// ----------------------- Utilities -----------------------
const uid = () => Math.random().toString(36).slice(2, 9);
const money = (n) => (n || 0).toFixed(2) + ' AED';

// ----------------------- Demo Data -----------------------
const demoCategories = [
  { id: 'cat1', name: 'Cement & Mortar' },
  { id: 'cat2', name: 'Tiles & Flooring' },
  { id: 'cat3', name: 'Paints & Finishes' },
  { id: 'cat4', name: 'Plumbing' },
  { id: 'cat5', name: 'Electrical' },
];

const demoSuppliers = [
  { id: 'sup1', name: 'Al-Ashraf Supply', active: true },
  { id: 'sup2', name: 'Desert Tools Co.', active: true },
  { id: 'sup3', name: 'UAE Tiles', active: false },
];

const demoProducts = [
  { id: 'p1', supplierId: 'sup1', name: 'Ordinary Portland Cement 50kg', price: 25.0, categoryId: 'cat1', stock: 120, desc: 'High-quality OPC for general use.' },
  { id: 'p2', supplierId: 'sup1', name: 'Tile Adhesive 20kg', price: 40.0, categoryId: 'cat2', stock: 60, desc: 'Waterproof tile adhesive.' },
  { id: 'p3', supplierId: 'sup2', name: 'Electric Wire 2.5mm (100m)', price: 180.0, categoryId: 'cat5', stock: 30, desc: 'Copper core, fire-resistant.' },
  { id: 'p4', supplierId: 'sup2', name: 'PVC Pipe 3" (6m)', price: 60.0, categoryId: 'cat4', stock: 75, desc: 'Durable plumbing pipe.' },
  { id: 'p5', supplierId: 'sup3', name: 'Gloss Paint 4L', price: 95.0, categoryId: 'cat3', stock: 40, desc: 'Premium interior gloss paint.' },
];

// ----------------------- App Context -----------------------
const AppContext = createContext();
const useApp = () => useContext(AppContext);

function AppProvider({ children }) {
  // load from localStorage or use demo data
  const [categories, setCategories] = useState(() => JSON.parse(localStorage.getItem('bm:cats')) || demoCategories);
  const [suppliers, setSuppliers] = useState(() => JSON.parse(localStorage.getItem('bm:suppliers')) || demoSuppliers);
  const [products, setProducts] = useState(() => JSON.parse(localStorage.getItem('bm:products')) || demoProducts);
  const [orders, setOrders] = useState(() => JSON.parse(localStorage.getItem('bm:orders')) || []);

  useEffect(() => { localStorage.setItem('bm:cats', JSON.stringify(categories)); }, [categories]);
  useEffect(() => { localStorage.setItem('bm:suppliers', JSON.stringify(suppliers)); }, [suppliers]);
  useEffect(() => { localStorage.setItem('bm:products', JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem('bm:orders', JSON.stringify(orders)); }, [orders]);

  const api = {
    categories,
    suppliers,
    products,
    orders,
    addCategory: (name) => { const c = { id: uid(), name }; setCategories(s => [...s, c]); return c; },
    updateCategory: (id, name) => setCategories(s => s.map(c => c.id === id ? { ...c, name } : c)),
    addSupplier: (name) => { const s = { id: uid(), name, active: true }; setSuppliers(x => [...x, s]); return s; },
    setSupplierActive: (id, active) => setSuppliers(s => s.map(x => x.id === id ? { ...x, active } : x)),
    addProduct: (p) => { const prod = { ...p, id: uid() }; setProducts(x => [...x, prod]); return prod; },
    updateProduct: (id, patch) => setProducts(x => x.map(p => p.id === id ? { ...p, ...patch } : p)),
    deleteProduct: (id) => setProducts(x => x.filter(p => p.id !== id)),
    placeOrder: (order) => { const o = { ...order, id: 'ord_' + uid(), status: 'placed', createdAt: new Date().toISOString() }; setOrders(x => [...x, o]); return o; },
    markDelivered: (orderId, driverId) => setOrders(x => x.map(o => o.id === orderId ? { ...o, status: 'delivered', deliveredBy: driverId, deliveredAt: new Date().toISOString() } : o)),
  };

  return <AppContext.Provider value={api}>{children}</AppContext.Provider>;
}

// ----------------------- Simple Auth + Role Selector (Demo) -----------------------
function RoleSelector({ onLogin }) {
  const [role, setRole] = useState('user');
  const [name, setName] = useState('');
  const { suppliers, addSupplier } = useApp();

  return (
    <div className="p-4 border rounded bg-white shadow-sm max-w-2xl mx-auto mt-6">
      <h3 className="text-lg font-semibold">Demo Login / Role</h3>
      <p className="text-sm text-muted">Choose a role to demo the corresponding interface.</p>
      <div className="mt-3 grid grid-cols-2 gap-3">
        <div>
          <label className="block">Name</label>
          <input value={name} onChange={e => setName(e.target.value)} className="border p-2 w-full" placeholder="Your name" />
        </div>
        <div>
          <label>Role</label>
          <select value={role} onChange={e => setRole(e.target.value)} className="border p-2 w-full">
            <option value="user">User / Customer</option>
            <option value="supplier">Supplier (register)</option>
            <option value="supplier-admin">Supplier Admin</option>
            <option value="superadmin">Super Admin</option>
            <option value="delivery">Delivery Driver</option>
          </select>
        </div>
      </div>
      <div className="mt-4 flex gap-2">
        <button className="px-4 py-2 rounded bg-blue-600 text-white" onClick={() => onLogin({ role, name })}>Enter</button>
        {role === 'supplier' && <button className="px-4 py-2 rounded bg-green-600 text-white" onClick={() => { if (!name) return alert('enter name'); const s = addSupplier(name); alert('Registered supplier ' + s.name + ' (id:'+s.id+')'); }}>Quick Register</button>}
      </div>
    </div>
  );
}

// ----------------------- Super Admin -----------------------
function SuperAdmin() {
  const { categories, suppliers, setSupplierActive, addCategory, updateCategory } = useApp();
  const [newCat, setNewCat] = useState('');

  return (
    <div className="p-4">
      <h2 className="text-xl font-bold">Super Admin Dashboard</h2>
      <section className="mt-4 bg-white p-4 rounded shadow">
        <h3 className="font-semibold">Categories</h3>
        <div className="mt-2 grid grid-cols-2 gap-3">
          <input value={newCat} onChange={e => setNewCat(e.target.value)} className="border p-2" placeholder="New category name" />
          <button className="px-3 py-2 bg-green-600 text-white rounded" onClick={() => { if (!newCat) return; addCategory(newCat); setNewCat(''); }}>Add</button>
        </div>
        <ul className="mt-3">
          {categories.map(c => <li key={c.id} className="flex justify-between items-center border-b py-2">{c.name} <button className="text-sm text-blue-600" onClick={() => { const val = prompt('Rename category', c.name); if (val) updateCategory(c.id, val); }}>Rename</button></li>)}
        </ul>
      </section>

      <section className="mt-4 bg-white p-4 rounded shadow">
        <h3 className="font-semibold">Suppliers</h3>
        <table className="w-full mt-2">
          <thead><tr><th className="text-left">Name</th><th>Status</th><th>Actions</th></tr></thead>
          <tbody>
            {suppliers.map(s => (
              <tr key={s.id} className="border-t">
                <td>{s.name}</td>
                <td>{s.active ? 'Active' : 'Inactive'}</td>
                <td>
                  <button className="px-2 py-1 mr-2 rounded bg-yellow-500 text-white" onClick={() => setSupplierActive(s.id, !s.active)}>{s.active ? 'Deactivate' : 'Activate'}</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </section>
    </div>
  );
}

// ----------------------- Supplier Admin Interface -----------------------
function SupplierAdmin({ supplierId }) {
  const { products, categories, addProduct, updateProduct, deleteProduct } = useApp();
  const myProducts = products.filter(p => p.supplierId === supplierId);
  const [form, setForm] = useState({ name: '', price: 0, categoryId: categories[0]?.id || '', stock: 0, desc: '' });

  function submit(e) { e.preventDefault(); addProduct({ ...form, supplierId }); setForm({ name: '', price: 0, categoryId: categories[0]?.id || '', stock: 0, desc: '' }); }

  return (
    <div className="p-4">
      <h2 className="text-xl font-bold">Supplier Admin - Products</h2>
      <div className="mt-3 bg-white p-4 rounded shadow">
        <form onSubmit={submit} className="grid grid-cols-2 gap-3">
          <input required placeholder="Product name" value={form.name} onChange={e => setForm({ ...form, name: e.target.value })} className="border p-2" />
          <input type="number" required placeholder="Price (AED)" value={form.price} onChange={e => setForm({ ...form, price: parseFloat(e.target.value) || 0 })} className="border p-2" />
          <select value={form.categoryId} onChange={e => setForm({ ...form, categoryId: e.target.value })} className="border p-2">
            {categories.map(c => <option key={c.id} value={c.id}>{c.name}</option>)}
          </select>
          <input type="number" placeholder="Stock" value={form.stock} onChange={e => setForm({ ...form, stock: parseInt(e.target.value || 0) })} className="border p-2" />
          <textarea placeholder="Description" value={form.desc} onChange={e => setForm({ ...form, desc: e.target.value })} className="border p-2 col-span-2" />
          <div className="col-span-2 text-right"><button className="px-4 py-2 bg-blue-600 text-white rounded">Add Product</button></div>
        </form>
      </div>

      <div className="mt-4 bg-white p-4 rounded shadow">
        <h3 className="font-semibold">My Products</h3>
        <ul>
          {myProducts.map(p => (
            <li key={p.id} className="border-b py-2 flex justify-between items-center">
              <div>
                <div className="font-semibold">{p.name} — {money(p.price)}</div>
                <div className="text-sm text-muted">Stock: {p.stock} | {p.desc}</div>
              </div>
              <div>
                <button className="px-2 py-1 mr-2 bg-yellow-500 rounded" onClick={() => { const price = prompt('New price AED', p.price); if (price) updateProduct(p.id, { price: parseFloat(price) }); }}>Edit</button>
                <button className="px-2 py-1 bg-red-600 text-white rounded" onClick={() => { if (confirm('Delete product?')) deleteProduct(p.id); }}>Delete</button>
              </div>
            </li>
          ))}
        </ul>
      </div>
    </div>
  );
}

// ----------------------- Marketplace / User -----------------------
function Marketplace({ onAddToCart }) {
  const { products, categories, suppliers } = useApp();
  const [catFilter, setCatFilter] = useState('');
  const [search, setSearch] = useState('');
  const [sort, setSort] = useState('relevant');

  const activeSuppliers = new Set(suppliers.filter(s => s.active).map(s => s.id));
  let list = products.filter(p => activeSuppliers.has(p.supplierId));
  if (catFilter) list = list.filter(p => p.categoryId === catFilter);
  if (search) list = list.filter(p => p.name.toLowerCase().includes(search.toLowerCase()) || p.desc.toLowerCase().includes(search.toLowerCase()));
  if (sort === 'price_asc') list.sort((a,b)=>a.price-b.price);
  if (sort === 'price_desc') list.sort((a,b)=>b.price-a.price);

  return (
    <div className="p-4">
      <h2 className="text-xl font-bold">Marketplace</h2>
      <div className="mt-3 grid grid-cols-4 gap-3">
        <input className="col-span-2 border p-2" placeholder="Search products" value={search} onChange={e=>setSearch(e.target.value)} />
        <select value={catFilter} onChange={e=>setCatFilter(e.target.value)} className="border p-2">
          <option value="">All Categories</option>
          {categories.map(c=> <option key={c.id} value={c.id}>{c.name}</option>)}
        </select>
        <select value={sort} onChange={e=>setSort(e.target.value)} className="border p-2">
          <option value="relevant">Most relevant</option>
          <option value="price_asc">Price: Low to High</option>
          <option value="price_desc">Price: High to Low</option>
        </select>
      </div>

      <div className="mt-4 grid grid-cols-3 gap-4">
        {list.map(p => (
          <div key={p.id} className="bg-white p-3 rounded shadow">
            <div className="font-semibold">{p.name}</div>
            <div className="text-sm text-muted">{p.desc}</div>
            <div className="mt-2 font-bold">{money(p.price)}</div>
            <div className="mt-2 flex gap-2">
              <button className="px-3 py-1 bg-green-600 text-white rounded" onClick={()=>onAddToCart(p,1)}>Add to cart</button>
              <button className="px-3 py-1 bg-gray-200 rounded" onClick={()=>alert('Product details modal placeholder')}>Details</button>
            </div>
          </div>
        ))}
      </div>
    </div>
  );
}

// ----------------------- Cart / Checkout / Invoice -----------------------
function Cart({ cart, setCart, onPlaceOrder }) {
  const [payment, setPayment] = useState('cod');
  const subtotal = cart.reduce((s,it)=>s + it.product.price * it.qty, 0);
  const deliveryFee = subtotal > 500 ? 0 : 25; // simple rule
  const total = subtotal + deliveryFee;

  function changeQty(id, q){ setCart(c=> c.map(i=> i.product.id===id ? {...i,qty:q}: i)); }
  function remove(id){ setCart(c=> c.filter(i=> i.product.id!==id)); }

  return (
    <div className="p-4">
      <h3 className="text-lg font-bold">Cart</h3>
      <div className="mt-3 bg-white p-4 rounded shadow">
        {cart.length===0 && <div>Cart is empty</div>}
        <ul>
          {cart.map(it => (
            <li key={it.product.id} className="flex justify-between items-center border-b py-2">
              <div><div className="font-semibold">{it.product.name}</div><div className="text-sm">{money(it.product.price)} x {it.qty}</div></div>
              <div className="flex items-center gap-2">
                <input className="w-16 border p-1" type="number" min={1} value={it.qty} onChange={e=>changeQty(it.product.id, Math.max(1, parseInt(e.target.value||1)))} />
                <button className="px-3 py-1 bg-red-600 text-white rounded" onClick={()=>remove(it.product.id)}>Remove</button>
              </div>
            </li>
          ))}
        </ul>
        <div className="mt-3 text-right">
          <div>Subtotal: {money(subtotal)}</div>
          <div>Delivery: {money(deliveryFee)}</div>
          <div className="font-bold">Total: {money(total)}</div>
        </div>
        <div className="mt-3">
          <label className="block">Payment</label>
          <select value={payment} onChange={e=>setPayment(e.target.value)} className="border p-2 w-48">
            <option value="cod">Cash on Delivery</option>
            <option value="card">Card Payment (demo)</option>
          </select>
        </div>
        <div className="mt-3 text-right">
          <button className="px-4 py-2 bg-blue-600 text-white rounded" onClick={()=>onPlaceOrder({payment, subtotal, deliveryFee, total})} disabled={cart.length===0}>Place Order</button>
        </div>
      </div>
    </div>
  );
}

// ----------------------- Delivery Interface -----------------------
function Delivery({ driverId }) {
  const { orders, markDelivered } = useApp();
  const pending = orders.filter(o => o.status === 'placed');
  const delivered = orders.filter(o => o.status === 'delivered');

  return (
    <div className="p-4">
      <h2 className="text-xl font-bold">Delivery Dashboard (Driver: {driverId})</h2>
      <div className="mt-3 grid grid-cols-2 gap-4">
        <div className="bg-white p-3 rounded shadow">
          <h3 className="font-semibold">Pending Orders</h3>
          {pending.length===0 && <div className="text-sm">No pending orders</div>}
          <ul>
            {pending.map(o => (
              <li key={o.id} className="border-b py-2">
                <div className="font-semibold">Order {o.id}</div>
                <div className="text-sm">Total: {money(o.total)} | Payment: {o.payment}</div>
                <div className="mt-2 text-right"><button className="px-3 py-1 bg-green-600 text-white rounded" onClick={()=>markDelivered(o.id, driverId)}>Mark Delivered</button></div>
              </li>
            ))}
          </ul>
        </div>

        <div className="bg-white p-3 rounded shadow">
          <h3 className="font-semibold">Delivered Orders</h3>
          <ul>
            {delivered.map(o => <li key={o.id} className="border-b py-2">{o.id} — delivered at {o.deliveredAt}</li>)}
          </ul>
        </div>
      </div>
    </div>
  );
}

// ----------------------- Invoice Modal -----------------------
function InvoiceModal({ order, onClose }) {
  if (!order) return null;
  return (
    <div className="fixed inset-0 bg-black bg-opacity-40 flex items-center justify-center">
      <div className="bg-white p-4 rounded w-3/4 max-h-[80vh] overflow-auto">
        <div className="flex justify-between items-center">
          <h3 className="text-xl font-bold">Invoice — {order.id}</h3>
          <button className="px-3 py-1 bg-gray-200 rounded" onClick={onClose}>Close</button>
        </div>
        <div className="mt-4">
          <div><strong>Date:</strong> {new Date(order.createdAt).toLocaleString()}</div>
          <div><strong>Payment:</strong> {order.payment}</div>
          <table className="w-full mt-3 border-collapse">
            <thead><tr><th className="text-left">Item</th><th>Qty</th><th>Price</th><th>Total</th></tr></thead>
            <tbody>
              {order.items.map(it => (
                <tr key={it.product.id}><td>{it.product.name}</td><td className="text-center">{it.qty}</td><td className="text-center">{money(it.product.price)}</td><td className="text-center">{money(it.product.price * it.qty)}</td></tr>
              ))}
            </tbody>
          </table>
          <div className="mt-3 text-right">
            <div>Subtotal: {money(order.subtotal)}</div>
            <div>Delivery: {money(order.deliveryFee)}</div>
            <div className="font-bold">Total: {money(order.total)}</div>
          </div>
        </div>
      </div>
    </div>
  );
}

// ----------------------- Main Demo App -----------------------
export default function BuildingMaterialsDemo() {
  const [user, setUser] = useState(null); // { role, name, supplierId?, id }
  const api = useApp();
  const [cart, setCart] = useState(() => JSON.parse(localStorage.getItem('bm:cart')) || []);
  const [invoiceOrder, setInvoiceOrder] = useState(null);

  useEffect(() => { localStorage.setItem('bm:cart', JSON.stringify(cart)); }, [cart]);

  function handleLogin({ role, name }){
    const id = uid();
    if (role === 'supplier-admin'){
      // pick first active supplier for demo
      const sup = api.suppliers[0];
      setUser({ role, name: name || 'SupplierAdmin', id, supplierId: sup?.id });
      return;
    }
    if (role === 'supplier'){
      // simulate registration then supplier admin
      const sup = api.suppliers[api.suppliers.length-1];
      setUser({ role: 'supplier-admin', name: name || sup?.name, id, supplierId: sup?.id });
      return;
    }
    setUser({ role, name: name || role, id });
  }

  function logout(){ setUser(null); }

  function addToCart(product, qty){ setCart(c => { const found = c.find(i=>i.product.id===product.id); if (found) return c.map(i=> i.product.id===product.id ? {...i, qty: i.qty+qty} : i); return [...c, { product, qty }]; }); }

  function placeOrder({payment, subtotal, deliveryFee, total}){
    const order = api.placeOrder({ items: cart, payment, subtotal, deliveryFee, total, user: { id: user?.id || 'guest', name: user?.name || 'Guest' } });
    setCart([]);
    setInvoiceOrder(order);
    alert('Order placed: ' + order.id);
  }

  return (
    <AppProvider>
      <div className="min-h-screen bg-gray-50 p-4">
        <header className="max-w-6xl mx-auto flex justify-between items-center">
          <h1 className="text-2xl font-bold">Building Materials Marketplace — Demo (AED)</h1>
          <div>
            {user ? (<div className="flex items-center gap-2"><div>{user.name} ({user.role})</div><button className="px-3 py-1 bg-gray-200 rounded" onClick={logout}>Logout</button></div>) : (<RoleSelector onLogin={handleLogin} />)}
          </div>
        </header>

        <main className="max-w-6xl mx-auto mt-6">
          {!user && (<div className="bg-white p-6 rounded shadow">Welcome! Please pick a role to explore the demo interfaces (superadmin / supplier-admin / user / delivery).</div>)}

          {user?.role === 'superadmin' && <SuperAdmin />}
          {user?.role === 'supplier-admin' && <SupplierAdmin supplierId={user.supplierId} />}
          {user?.role === 'user' && <div className="grid grid-cols-3 gap-4">
            <div className="col-span-2 bg-white rounded shadow"><Marketplace onAddToCart={addToCart} /></div>
            <div className="bg-white rounded shadow p-3"><Cart cart={cart} setCart={setCart} onPlaceOrder={placeOrder} /></div>
          </div>}
          {user?.role === 'delivery' && <Delivery driverId={user.id} />}

          <div className="mt-6">
            <h3 className="font-semibold">Customer Support / Settings (like noon)</h3>
            <div className="bg-white p-4 rounded shadow">
              <p className="text-sm">Support chat placeholder, order tracking, cancelation rules, return policy, seller contact details, and payment settings would live here. For demo we show quick actions:</p>
              <div className="mt-3 flex gap-2">
                <button className="px-3 py-1 bg-blue-600 text-white rounded" onClick={()=>alert('Open support chat (demo)')}>Chat Support</button>
                <button className="px-3 py-1 bg-gray-200 rounded" onClick={()=>alert('Open order tracking (demo)')}>Track Order</button>
              </div>
            </div>
          </div>

        </main>

        {invoiceOrder && <InvoiceModal order={invoiceOrder} onClose={()=>setInvoiceOrder(null)} />}

      </div>
    </AppProvider>
  );
}

