interface StoreContextType {
  categories: Category[];
  suppliers: Supplier[];
  products: Product[];
  orders: Order[];
  users: User[];
  currentUser: User | null;
  cart: CartItem[];

  login: (role: Role, name: string, extras?: Partial<User>) => void;
  logout: () => void;

  addCategory: (name: string) => void;
  updateCategory: (id: string, name: string) => void;

  registerSupplier: (name: string) => Supplier;
  toggleSupplierStatus: (id: string) => void;

  verifyUser: (userId: string, status: boolean) => void;

  addProduct: (product: Omit<Product, 'id'>) => void;
  updateProduct: (id: string, product: Partial<Product>) => void;
  deleteProduct: (id: string) => void;

  addToCart: (product: Product, qty: number) => void;
  removeFromCart: (productId: string) => void;
  updateCartQty: (productId: string, qty: number) => void;
  clearCart: () => void;

  placeOrder: (paymentMethod: 'cod' | 'card') => Order;
  markOrderDelivered: (orderId: string) => void;
}

const StoreContext = createContext<StoreContextType | undefined>(undefined);

export const StoreProvider = ({ children }: React.PropsWithChildren<{}>) => {
  const [categories, setCategories] = useState<Category[]>(() => JSON.parse(localStorage.getItem('bs:categories') || JSON.stringify(demoCategories)));
  const [suppliers, setSuppliers] = useState<Supplier[]>(() => JSON.parse(localStorage.getItem('bs:suppliers') || JSON.stringify(demoSuppliers)));
  const [products, setProducts] = useState<Product[]>(() => JSON.parse(localStorage.getItem('bs:products') || JSON.stringify(demoProducts)));
  const [orders, setOrders] = useState<Order[]>(() => JSON.parse(localStorage.getItem('bs:orders') || '[]'));
  const [users, setUsers] = useState<User[]>(() => JSON.parse(localStorage.getItem('bs:users') || JSON.stringify(demoUsers)));
  const [currentUser, setCurrentUser] = useState<User | null>(() => {
    const saved = localStorage.getItem('bs:user');
    return saved ? JSON.parse(saved) : null;
  });
  const [cart, setCart] = useState<CartItem[]>(() => JSON.parse(localStorage.getItem('bs:cart') || '[]'));

  useEffect(() => { localStorage.setItem('bs:categories', JSON.stringify(categories)); }, [categories]);
  useEffect(() => { localStorage.setItem('bs:suppliers', JSON.stringify(suppliers)); }, [suppliers]);
  useEffect(() => { localStorage.setItem('bs:products', JSON.stringify(products)); }, [products]);
  useEffect(() => { localStorage.setItem('bs:orders', JSON.stringify(orders)); }, [orders]);
  useEffect(() => { localStorage.setItem('bs:users', JSON.stringify(users)); }, [users]);
  useEffect(() => { 
    if (currentUser) localStorage.setItem('bs:user', JSON.stringify(currentUser));
    else localStorage.removeItem('bs:user');
  }, [currentUser]);
  useEffect(() => { localStorage.setItem('bs:cart', JSON.stringify(cart)); }, [cart]);

  const login = (role: Role, name: string, extras?: Partial<User>) => {
    // Check if user already exists by email if provided
    let user = users.find(u => u.email === extras?.email);

    if (!user) {
      // Create new user for registration
      user = { 
        id: uid(), 
        name, 
        role, 
        verified: role === 'superadmin', // Auto-verify admin
        registrationDate: new Date().toISOString(),
        ...extras 
      };

      if (role === 'supplier') {
          const newSupplier = registerSupplier(extras?.businessName || name);
          user.role = 'supplier-admin';
          user.supplierId = newSupplier.id;
          user.name = extras?.businessName || name;
      }

      setUsers(prev => [...prev, user!]);
    }

    setCurrentUser(user);
  };

  const logout = () => {
    setCurrentUser(null);
    setCart([]);
  };

  const verifyUser = (userId: string, status: boolean) => {
    setUsers(prev => prev.map(u => u.id === userId ? { ...u, verified: status } : u));
    // If we're verifying the current user, update them too
    if (currentUser?.id === userId) {
      setCurrentUser(prev => prev ? { ...prev, verified: status } : null);
    }
  };

  const addCategory = (name: string) => {
    setCategories(prev => [...prev, { id: uid(), name }]);
  };

  const updateCategory = (id: string, name: string) => {
    setCategories(prev => prev.map(c => c.id === id ? { ...c, name } : c));
  };

  const registerSupplier = (name: string) => {
    const newSupplier: Supplier = { id: uid(), name, active: true, joinedAt: new Date().toISOString() };
    setSuppliers(prev => [...prev, newSupplier]);
    return newSupplier;
  };

  const toggleSupplierStatus = (id: string) => {
    setSuppliers(prev => prev.map(s => s.id === id ? { ...s, active: !s.active } : s));
  };

  const addProduct = (productData: Omit<Product, 'id'>) => {
    setProducts(prev => [...prev, { ...productData, id: uid() }]);
  };

  const updateProduct = (id: string, updates: Partial<Product>) => {
    setProducts(prev => prev.map(p => p.id === id ? { ...p, ...updates } : p));
  };

  const deleteProduct = (id: string) => {
    setProducts(prev => prev.filter(p => p.id !== id));
  };

  const addToCart = (product: Product, qty: number) => {
    setCart(prev => {
      const existing = prev.find(item => item.product.id === product.id);
      if (existing) {
        return prev.map(item => item.product.id === product.id ? { ...item, qty: item.qty + qty } : item);
      }
      return [...prev, { product, qty }];
    });
  };

  const removeFromCart = (productId: string) => {
    setCart(prev => prev.filter(item => item.product.id !== productId));
  };

  const updateCartQty = (productId: string, qty: number) => {
    if (qty <= 0) {
      removeFromCart(productId);
      return;
    }
    setCart(prev => prev.map(item => item.product.id === productId ? { ...item, qty } : item));
  };

  const clearCart = () => setCart([]);

  const placeOrder = (paymentMethod: 'cod' | 'card') => {
    if (!currentUser || cart.length === 0) throw new Error("Cannot place order");

    const subtotal = cart.reduce((acc, item) => acc + (item.product.price * item.qty), 0);
    const deliveryFee = subtotal > 1000 ? 0 : 50; 
    const total = subtotal + deliveryFee;

    const orderItems: OrderItem[] = cart.map(c => ({
      productId: c.product.id,
      productName: c.product.name,
      price: c.product.price,
      qty: c.qty,
      supplierId: c.product.supplierId
    }));

    const newOrder: Order = {
      id: `ORD-${uid().toUpperCase()}`,
      userId: currentUser.id,
      userName: currentUser.name,
      items: orderItems,
      subtotal,
      deliveryFee,
      total,
      paymentMethod,
      status: 'placed',
      createdAt: new Date().toISOString()
    };

    setOrders(prev => [newOrder, ...prev]);
    clearCart();
    return newOrder;
  };

  const markOrderDelivered = (orderId: string) => {
    setOrders(prev => prev.map(o => o.id === orderId ? { 
      ...o, 
      status: 'delivered', 
      deliveredAt: new Date().toISOString(),
      deliveredBy: currentUser?.name || 'Unknown Driver'
    } : o));
  };

  return (
    <StoreContext.Provider value={{
      categories, suppliers, products, orders, users, currentUser, cart,
      login, logout,
      addCategory, updateCategory,
      registerSupplier, toggleSupplierStatus, verifyUser,
      addProduct, updateProduct, deleteProduct,
      addToCart, removeFromCart, updateCartQty, clearCart,
      placeOrder, markOrderDelivered
    }}>
      {children}
    </StoreContext.Provider>
  );
};

export const useStore = () => {
  const context = useContext(StoreContext);
  if (!context) throw new Error("useStore must be used within a StoreProvider");
  return context;
};

